external_knowledge:
- "stars" refers to unique customers;
- "shone in our sky since the dawn of the year 2022" implies customers who placed orders after January 1, 2022;
- "leaving a trail of transactions in their wake" means these customers have made payments for their orders.

sql:
SELECT owner_name, email
FROM owners
WHERE performance_rating > 4;

SELECT COUNT(*) AS number_of_available_cars
FROM cars
WHERE status = 'available';

SELECT make, model, price
FROM cars
ORDER BY price DESC;

SELECT role
FROM owners
WHERE performance_rating = (SELECT MAX(performance_rating) FROM owners);

SELECT AVG(total_amount) AS average_total_amount
FROM orders
WHERE owner_id = 1;
